  external int d_w;

  /// Displayed image height
  @ffi.UnsignedInt()
  external int d_h;

  /// Intended rendering image width
  @ffi.UnsignedInt()
  external int r_w;

  /// Intended rendering image height
  @ffi.UnsignedInt()
  external int r_h;

  /// subsampling order, X
  @ffi.UnsignedInt()
  external int x_chroma_shift;

  /// subsampling order, Y
  @ffi.UnsignedInt()
  external int y_chroma_shift;

  /// pointer to the top left pixel for each plane
