  external vpx_fixed_buf_t rc_firstpass_mb_stats_in;

  /// Target data rate
  @ffi.UnsignedInt()
  external int rc_target_bitrate;

  /// Minimum (Best Quality) Quantizer
  @ffi.UnsignedInt()
  external int rc_min_quantizer;

  /// Maximum (Worst Quality) Quantizer
  @ffi.UnsignedInt()
  external int rc_max_quantizer;

  /// Rate control adaptation undershoot control
  @ffi.UnsignedInt()
  external int rc_undershoot_pct;

  /// Rate control adaptation overshoot control
  @ffi.UnsignedInt()
  external int rc_overshoot_pct;

  /// Decoder Buffer Size
  @ffi.UnsignedInt()
  external int rc_buf_sz;

  /// Decoder Buffer Initial Size
  @ffi.UnsignedInt()
  external int rc_buf_initial_sz;

  /// Decoder Buffer Optimal Size
  @ffi.UnsignedInt()
  external int rc_buf_optimal_sz;

  /// Two-pass mode CBR/VBR bias
  @ffi.UnsignedInt()
  external int rc_2pass_vbr_bias_pct;

  /// Two-pass mode per-GOP minimum bitrate
  @ffi.UnsignedInt()
  external int rc_2pass_vbr_minsection_pct;

  /// Two-pass mode per-GOP maximum bitrate
  @ffi.UnsignedInt()
  external int rc_2pass_vbr_maxsection_pct;

  /// Two-pass corpus vbr mode complexity control Used only in VP9: A value
  /// representing the corpus midpoint complexity for corpus vbr mode. This
  /// value defaults to 0 which disables corpus vbr mode in favour of normal vbr
  /// mode.
  @ffi.UnsignedInt()
  external int rc_2pass_vbr_corpus_complexity;

  /// Keyframe placement mode
  @ffi.UnsignedInt()
  external int kf_modeAsInt;

  vpx_kf_mode get kf_mode => vpx_kf_mode.fromValue(kf_modeAsInt);

  /// Keyframe minimum interval
  @ffi.UnsignedInt()
  external int kf_min_dist;

  /// Keyframe maximum interval
  @ffi.UnsignedInt()
  external int kf_max_dist;

  /// Number of spatial coding layers.
  @ffi.UnsignedInt()
  external int ss_number_layers;

  /// Enable auto alt reference flags for each spatial layer.
  @ffi.Array.multi([5])
  external ffi.Array<ffi.Int> ss_enable_auto_alt_ref;

  /// Target bitrate for each spatial layer.
  @ffi.Array.multi([5])
  external ffi.Array<ffi.UnsignedInt> ss_target_bitrate;

  /// Number of temporal coding layers.
  @ffi.UnsignedInt()
  external int ts_number_layers;

  /// Target bitrate for each temporal layer.
  @ffi.Array.multi([5])
  external ffi.Array<ffi.UnsignedInt> ts_target_bitrate;

  /// Frame rate decimation factor for each temporal layer.
  @ffi.Array.multi([5])
  external ffi.Array<ffi.UnsignedInt> ts_rate_decimator;

  /// Length of the sequence defining frame temporal layer membership.
  @ffi.UnsignedInt()
  external int ts_periodicity;

  /// Template defining the membership of frames to temporal layers.
  @ffi.Array.multi([16])
  external ffi.Array<ffi.UnsignedInt> ts_layer_id;

  /// Target bitrate for each spatial/temporal layer.
  @ffi.Array.multi([12])
  external ffi.Array<ffi.UnsignedInt> layer_target_bitrate;

  /// Temporal layering mode indicating which temporal layering scheme to use.
  @ffi.Int()
  external int temporal_layering_mode;

  /// A flag indicating whether to use external rate control parameters. By
  /// default is 0. If set to 1, the following parameters will be used in the
  /// rate control system.
  @ffi.Int()
  external int use_vizier_rc_params;

  /// Active worst quality factor.
  external vpx_rational_t active_wq_factor;

  /// Error per macroblock adjustment factor.
  external vpx_rational_t err_per_mb_factor;

  /// Second reference default decay limit.
  external vpx_rational_t sr_default_decay_limit;

  /// Second reference difference factor.
  external vpx_rational_t sr_diff_factor;

  /// Keyframe error per macroblock adjustment factor.
  external vpx_rational_t kf_err_per_mb_factor;

  /// Keyframe minimum boost adjustment factor.
  external vpx_rational_t kf_frame_min_boost_factor;

  /// Keyframe maximum boost adjustment factor, for the first keyframe in a
  /// chunk.
  external vpx_rational_t kf_frame_max_boost_first_factor;

  /// Keyframe maximum boost adjustment factor, for subsequent keyframes.
  external vpx_rational_t kf_frame_max_boost_subs_factor;

  /// Keyframe maximum total boost adjustment factor.
  external vpx_rational_t kf_max_total_boost_factor;

  /// Golden frame maximum total boost adjustment factor.
  external vpx_rational_t gf_max_total_boost_factor;

  /// Golden frame maximum boost adjustment factor.
  external vpx_rational_t gf_frame_max_boost_factor;

  /// Zero motion power factor.
  external vpx_rational_t zm_factor;

  /// Rate-distortion multiplier for inter frames. The multiplier is a crucial
  /// parameter in the calculation of rate distortion cost. It is often related
  /// to the qp (qindex) value. Rate control parameters, could be set from
  /// external experiment results. Only when |use_vizier_rc_params| is set to 1,
  /// the pass in value will be used. Otherwise, the default value is used.
  external vpx_rational_t rd_mult_inter_qp_fac;

  /// Rate-distortion multiplier for alt-ref frames. The multiplier is a crucial
  /// parameter in the calculation of rate distortion cost. It is often related
  /// to the qp (qindex) value. Rate control parameters, could be set from
  /// external experiment results. Only when |use_vizier_rc_params| is set to 1,
  /// the pass in value will be used. Otherwise, the default value is used.
  external vpx_rational_t rd_mult_arf_qp_fac;

  /// Rate-distortion multiplier for key frames. The multiplier is a crucial
  /// parameter in the calculation of rate distortion cost. It is often related
  /// to the qp (qindex) value. Rate control parameters, could be set from
  /// external experiment results. Only when |use_vizier_rc_params| is set to 1,
  /// the pass in value will be used. Otherwise, the default value is used.
  external vpx_rational_t rd_mult_key_qp_fac;
}

