/// The control type of the inference API. In VPX_RC_QP mode, the external rate
/// control model determines the quantization parameter (QP) for each frame. In
/// VPX_RC_GOP mode, the external rate control model determines the group of
/// picture (GOP) of the video sequence. In VPX_RC_RDMULT mode, the external
/// rate control model determines the rate-distortion multiplier (rdmult) for
/// the current frame. In VPX_RC_GOP_QP mode, the external rate control model
/// determines both the QP and the GOP. In VPX_RC_GOP_QP_RDMULT mode, the
/// external rate control model determines the QP, GOP and the rdmult.
enum vpx_rc_type {
  VPX_RC_QP(1),
  VPX_RC_GOP(2),
  VPX_RC_RDMULT(4),
  VPX_RC_GOP_QP(3),
  VPX_RC_GOP_QP_RDMULT(7);

  final int value;
  const vpx_rc_type(this.value);

  static vpx_rc_type fromValue(int value) => switch (value) {
    1 => VPX_RC_QP,
    2 => VPX_RC_GOP,
    4 => VPX_RC_RDMULT,
    3 => VPX_RC_GOP_QP,
    7 => VPX_RC_GOP_QP_RDMULT,
    _ => throw ArgumentError('Unknown value for vpx_rc_type: $value'),
  };
}

/// The rate control mode for the external rate control model.
enum vpx_ext_rc_mode {
  VPX_RC_QMODE(0),
  VPX_RC_VBR(1),
  VPX_RC_CQ(2);

  final int value;
  const vpx_ext_rc_mode(this.value);

  static vpx_ext_rc_mode fromValue(int value) => switch (value) {
    0 => VPX_RC_QMODE,
    1 => VPX_RC_VBR,
    2 => VPX_RC_CQ,
    _ => throw ArgumentError('Unknown value for vpx_ext_rc_mode: $value'),
  };
}

