/// First pass frame stats This is a mirror of vp9's FIRSTPASS_STATS except that
/// spatial_layer_id is omitted
final class vpx_rc_frame_stats extends ffi.Struct {
  /// Frame number in display order, if stats are for a single frame. No real
  /// meaning for a collection of frames.
  @ffi.Double()
