  VP8E_SET_TOKEN_PARTITIONS(18),

  /// Codec control function to get last quantizer chosen by the encoder.
  VP8E_GET_LAST_QUANTIZER(19),

  /// Codec control function to get last quantizer chosen by the encoder.
  VP8E_GET_LAST_QUANTIZER_64(20),

  /// Codec control function to set the max no of frames to create arf.
  VP8E_SET_ARNR_MAXFRAMES(21),

  /// Codec control function to set the filter strength for the arf.
  VP8E_SET_ARNR_STRENGTH(22),
  VP8E_SET_ARNR_TYPE(23),

  /// Codec control function to set visual tuning.
  VP8E_SET_TUNING(24),

  /// Codec control function to set constrained / constant quality level.
  VP8E_SET_CQ_LEVEL(25),

  /// Codec control function to set Max data rate for Intra frames.
  VP8E_SET_MAX_INTRA_BITRATE_PCT(26),

  /// Codec control function to set reference and update frame flags.
  VP8E_SET_FRAME_FLAGS(27),

  /// Codec control function to set max data rate for Inter frames.
  VP9E_SET_MAX_INTER_BITRATE_PCT(28),

  /// Boost percentage for Golden Frame in CBR mode.
  VP9E_SET_GF_CBR_BOOST_PCT(29),

  /// Codec control function to set the temporal layer id.
  VP8E_SET_TEMPORAL_LAYER_ID(30),

  /// Codec control function to set encoder screen content mode.
  VP8E_SET_SCREEN_CONTENT_MODE(31),

  /// Codec control function to set lossless encoding mode.
  VP9E_SET_LOSSLESS(32),

  /// Codec control function to set number of tile columns.
  VP9E_SET_TILE_COLUMNS(33),

  /// Codec control function to set number of tile rows.
  VP9E_SET_TILE_ROWS(34),

  /// Codec control function to enable frame parallel decoding feature.
  VP9E_SET_FRAME_PARALLEL_DECODING(35),

  /// Codec control function to set adaptive quantization mode.
  VP9E_SET_AQ_MODE(36),

  /// Codec control function to enable/disable periodic Q boost.
  VP9E_SET_FRAME_PERIODIC_BOOST(37),

  /// Codec control function to set noise sensitivity.
  VP9E_SET_NOISE_SENSITIVITY(38),

  /// Codec control function to turn on/off SVC in encoder.
  VP9E_SET_SVC(39),

  /// Codec control function to pass an ROI map to encoder.
  VP9E_SET_ROI_MAP(40),

  /// Codec control function to set parameters for SVC.
  VP9E_SET_SVC_PARAMETERS(41),

  /// Codec control function to set svc layer for spatial and temporal.
  VP9E_SET_SVC_LAYER_ID(42),

  /// Codec control function to set content type.
  VP9E_SET_TUNE_CONTENT(43),

  /// Codec control function to get svc layer ID.
  VP9E_GET_SVC_LAYER_ID(44),

  /// Codec control function to register callback to get per layer packet.
  VP9E_REGISTER_CX_CALLBACK(45),

  /// Codec control function to set color space info.
  VP9E_SET_COLOR_SPACE(46),

  /// Codec control function to set minimum interval between GF/ARF frames
  VP9E_SET_MIN_GF_INTERVAL(48),

  /// Codec control function to set minimum interval between GF/ARF frames
  VP9E_SET_MAX_GF_INTERVAL(49),

  /// Codec control function to get an Active map back from the encoder.
  VP9E_GET_ACTIVEMAP(50),

  /// Codec control function to set color range bit.
  VP9E_SET_COLOR_RANGE(51),

  /// Codec control function to set the frame flags and buffer indices for
  /// spatial layers. The frame flags and buffer indices are set using the
  /// struct #vpx_svc_ref_frame_config defined below.
  VP9E_SET_SVC_REF_FRAME_CONFIG(52),

  /// Codec control function to set intended rendering image size.
  VP9E_SET_RENDER_SIZE(53),

  /// Codec control function to set target level.
  VP9E_SET_TARGET_LEVEL(54),

  /// Codec control function to set row level multi-threading.
  VP9E_SET_ROW_MT(55),

  /// Codec control function to get bitstream level.
  VP9E_GET_LEVEL(56),

  /// Codec control function to enable/disable special mode for altref adaptive
  /// quantization. You can use it with --aq-mode concurrently.
  VP9E_SET_ALT_REF_AQ(57),

  /// Boost percentage for Golden Frame in CBR mode.
  VP8E_SET_GF_CBR_BOOST_PCT(58),

  /// Codec control function to enable the extreme motion vector unit test in
  /// VP9. Please note that this is only used in motion vector unit test.
  VP9E_ENABLE_MOTION_VECTOR_UNIT_TEST(59),

  /// Codec control function to constrain the inter-layer prediction (prediction
  /// of lower spatial resolution) in VP9 SVC.
  VP9E_SET_SVC_INTER_LAYER_PRED(60),

  /// Codec control function to set mode and thresholds for frame dropping in
  /// SVC. Drop frame thresholds are set per-layer. Mode is set as: 0 :
  /// layer-dependent dropping, 1 : constrained dropping, current layer drop
  /// forces drop on all upper layers. Default mode is 0.
  VP9E_SET_SVC_FRAME_DROP_LAYER(61),

  /// Codec control function to get the refresh and reference flags and the
  /// buffer indices, up to the last encoded spatial layer.
  VP9E_GET_SVC_REF_FRAME_CONFIG(62),

  /// Codec control function to enable/disable use of golden reference as a
  /// second temporal reference for SVC. Only used when inter-layer prediction
  /// is disabled on INTER frames.
  VP9E_SET_SVC_GF_TEMPORAL_REF(63),

  /// Codec control function to enable spatial layer sync frame, for any spatial
  /// layer. Enabling it for layer k means spatial layer k will disable all
  /// temporal prediction, but keep the inter-layer prediction. It will refresh
  /// any temporal reference buffer for that layer, and reset the temporal layer
  /// for the superframe to 0. Setting the layer sync for base spatial layer
  /// forces a key frame. Default is off (0) for all spatial layers. Spatial
  /// layer sync flag is reset to 0 after each encoded layer, so when control is
  /// invoked it is only used for the current superframe.
  VP9E_SET_SVC_SPATIAL_LAYER_SYNC(64),

  /// Codec control function to enable temporal dependency model.
  VP9E_SET_TPL(65),

  /// Codec control function to enable postencode frame drop.
  VP9E_SET_POSTENCODE_DROP(66),

  /// Codec control function to set delta q for uv.
  VP9E_SET_DELTA_Q_UV(67),

  /// Codec control function to disable increase Q on overshoot in CBR.
  VP9E_SET_DISABLE_OVERSHOOT_MAXQ_CBR(68),

  /// Codec control function to disable loopfilter.
  VP9E_SET_DISABLE_LOOPFILTER(69),

  /// Codec control function to enable external rate control library.
  VP9E_SET_EXTERNAL_RATE_CONTROL(70),

  /// Codec control to disable internal features in rate control.
  VP9E_SET_RTC_EXTERNAL_RATECTRL(71),

  /// Codec control function to get loopfilter level in the encoder.
  VP9E_GET_LOOPFILTER_LEVEL(72),

  /// Codec control to get last quantizers for all spatial layers.
  VP9E_GET_LAST_QUANTIZER_SVC_LAYERS(73),

  /// Codec control to disable internal features in rate control.
  VP8E_SET_RTC_EXTERNAL_RATECTRL(74),

  /// Codec control to set quantizer for the next frame.
  VP9E_SET_QUANTIZER_ONE_PASS(75);

  final int value;
  const vp8e_enc_control_id(this.value);

  static vp8e_enc_control_id fromValue(int value) => switch (value) {
    8 => VP8E_SET_ROI_MAP,
    9 => VP8E_SET_ACTIVEMAP,
    11 => VP8E_SET_SCALEMODE,
    13 => VP8E_SET_CPUUSED,
    14 => VP8E_SET_ENABLEAUTOALTREF,
    15 => VP8E_SET_NOISE_SENSITIVITY,
    16 => VP8E_SET_SHARPNESS,
    17 => VP8E_SET_STATIC_THRESHOLD,
    18 => VP8E_SET_TOKEN_PARTITIONS,
    19 => VP8E_GET_LAST_QUANTIZER,
